SELECT * FROM customer_behavior.customer;
-- Q1 what is the total revenue generated by male vs female customers?
select gender,sum(purchase_amount) as revenue
from customer
group by gender;
-- which customers used a discount but still spent more than actual purchase amount?
select customer_id,purchase_amount 
from customer
where discount_applied = 'Yes' and purchase_amount >= ( select avg(purchase_amount)  from customer );
-- which are the top 5 products with the highest average review rating?
select item_purchased , round(avg(review_rating),2) as "average product rating"
from customer
group by item_purchased
order by avg(review_rating) desc 
limit 5;
-- compare the average purchase amounts between standard and express shipping ?
select shipping_type,round(avg(purchase_amount),2)
from customer
where shipping_type in ('Standard','Express')
group by shipping_type;
-- Do subscribed customers spend more ,compare avg spend and total revenue between subscribed and non subscribed customers ?
select subscription_status ,
count(customer_id) as total_customer, 
avg(purchase_amount) as Average_Spend,
sum(purchase_amount) as total_revenue
from customer
group by subscription_status 
order by Average_Spend,total_revenue desc;
-- which 5 products have highest purchase percentage with discunts applied?
select item_purchased ,
round(sum(case when discount_applied = 'Yes' then 1 else 0 END) / COUNT(*) * 100.0,2) as discount_rate
from customer
group by item_purchased
order by discount_rate desc
limit 5;
-- segment customers into new,returning and loyal based on their total number of previous purchases,and show the count of eace segment
with customer_type as (
select customer_id,previous_purchases,
case
when previous_purchases = '1' then'NEW'
when previous_purchases between 2 and 10 then 'RETURNING'
else 'loyal'
end as customer_segment
from customer
)
select customer_segment,count(*) as "number of customers"
from customer_type 
group by customer_segment;
-- what are the top 3 most purchased products within each category?
with item_counts as (
select category,
item_purchased,
count(customer_id) as total_orders,
row_number() over (partition by category order by count(customer_id) desc) as item_rank
from customer
group by category,item_purchased
)
select item_rank,category,item_purchased,total_orders
from item_counts
where item_rank <= 3;
-- are customers who are repeat buyers( more than 5 previuos purchases) also likely to subscribe?
select subscription_status ,
count(customer_id) as repeat_buyers
from customer
where previous_purchases>5
group by subscription_status;
-- what is the revenue contibution of each age group
select age_group,
sum(purchase_amount) as total_revenue
from customer
group by age_group
order by total_revenue desc;
